+/// Request to capture a mailbox forensic bundle.
+#[derive(Debug, Clone, Copy)]
+pub struct MailboxForensicCapture<'a> {
+    pub command_name: &'a str,
+    pub trigger: &'a str,
+    pub database_url: &'a str,
+    pub db_path: &'a Path,
+    pub storage_root: &'a Path,
