+fn build_live_db_reference(capture: MailboxForensicCapture<'_>) -> serde_json::Value {
+    let wal_path = PathBuf::from(format!("{}-wal", capture.db_path.display()));
+    let shm_path = PathBuf::from(format!("{}-shm", capture.db_path.display()));
